WebLink.url:
{!REQUIRESCRIPT('/soap/ajax/47.0/connection.js')}
{!REQUIRESCRIPT('/soap/ajax/47.0/apex.js')}

//求職者IDを取得する
var recordId = '{!Human__c.Id}';

//ステータスが研修通知の場合
if('{!Human__c.Status__c}' == '研修通知'){
var result = sforce.apex.execute('SFTR_O_HumanWebService', 'attendRegist', {itemId:recordId});

if(result == '成功'){
alert('登録前研修・面談の受講登録が完了しました。');
window.location.reload();
} else {
alert('データの更新に失敗しました。');
}
} else {
alert('この処理は実行できません。');
}
